rag_raw:
{"control_id": "A.7.5", "applicable": "Yes", "implementation_status": "Implemented", "justification": "Sistem pemadam kebakaran otomatis dan UPS memberikan perlindungan terhadap ancaman fisik dan lingkungan, sesuai dengan A.7.5"},

{"control_id": "A.5.37", "applicable": "No", "implementation_status": "Not Implemented", "justification": "Sistem pemadam kebakaran otomatis dan UPS belum didokumentasikan atau tersedia bagi semua pengguna yang membutuhkannya, sesuai dengan A.5.37"},

{"control_id": "A.7.11", "applicable": "Yes", "implementation_status": "Implemented", "justification": "Sistem pemadam kebakaran otomatis dan UPS melindungi fasilitas pemrosesan informasi dari gagal utilitas, sesuai dengan A.7.11"}
